You are given a large Python module that implements a binary search tree. The module contains the following classes and methods:

class Node:
    def __init__(self, key, value=None):
        self.key = key
        self.value = value
        self.left = None
        self.right = None
        self.parent = None
        self.height = 1

class AVLTree:
    def __init__(self):
        self.root = None
        self.size = 0

    def insert(self, key, value=None):
        # Standard BST insert followed by AVL rebalancing
        node = Node(key, value)
        if self.root is None:
            self.root = node
            self.size += 1
            return
        current = self.root
        while True:
            if key < current.key:
                if current.left is None:
                    current.left = node
                    node.parent = current
                    break
                current = current.left
            elif key > current.key:
                if current.right is None:
                    current.right = node
                    node.parent = current
                    break
                current = current.right
            else:
                current.value = value
                return
        self.size += 1
        self._rebalance(node)

    def _rebalance(self, node):
        while node is not None:
            self._update_height(node)
            balance = self._balance_factor(node)
            if balance > 1:
                if self._balance_factor(node.left) < 0:
                    self._rotate_left(node.left)
                self._rotate_right(node)
            elif balance < -1:
                if self._balance_factor(node.right) > 0:
                    self._rotate_right(node.right)
                self._rotate_left(node)
            node = node.parent

    def _rotate_left(self, node):
        right = node.right
        node.right = right.left
        if right.left:
            right.left.parent = node
        right.parent = node.parent
        if node.parent is None:
            self.root = right
        elif node == node.parent.left:
            node.parent.left = right
        else:
            node.parent.right = right
        right.left = node
        node.parent = right
        self._update_height(node)
        self._update_height(right)

    def _rotate_right(self, node):
        left = node.left
        node.left = left.right
        if left.right:
            left.right.parent = node
        left.parent = node.parent
        if node.parent is None:
            self.root = left
        elif node == node.parent.right:
            node.parent.right = left
        else:
            node.parent.left = left
        left.right = node
        node.parent = left
        self._update_height(node)
        self._update_height(left)

    def _update_height(self, node):
        left_h = node.left.height if node.left else 0
        right_h = node.right.height if node.right else 0
        node.height = 1 + max(left_h, right_h)

    def _balance_factor(self, node):
        left_h = node.left.height if node.left else 0
        right_h = node.right.height if node.right else 0
        return left_h - right_h

Add a delete method that maintains the AVL balance property. Explain your approach step by step.
